import React, { useState, useEffect } from 'react';
import styles from './HappySmilers.module.css';

const SMILERS = [
  { id: 1, name: 'Aisha K.',  seed: 'woman-smile-1', bw: false },
  { id: 2, name: 'Priya S.',  seed: 'woman-smile-2', bw: false },
  { id: 3, name: 'Meera T.',  seed: 'woman-smile-3', bw: false },
  { id: 4, name: 'Rohan D.',  seed: 'man-smile-4',   bw: true  },
  { id: 5, name: 'Nisha R.',  seed: 'woman-smile-5', bw: false },
];

function randomPicsumUrl(seed, w = 300, h = 400) {
  return `https://picsum.photos/seed/${seed}/${w}/${h}`;
}

export default function HappySmilers() {
  const [smileImages, setSmileImages] = useState(
    SMILERS.map((s) => randomPicsumUrl(s.seed))
  );

  useEffect(() => {
    setSmileImages(SMILERS.map((s) => randomPicsumUrl(s.seed)));
  }, []);

  return (
    <section className={styles.section}>
      <div className={styles.inner}>
        <h2 className={styles.title}>Happy Smilers!</h2>

        <div className={styles.track}>
          {SMILERS.map((smiler, i) => (
            <div key={smiler.id} className={styles.card}>
              <div className={styles.frame}>

                {/* Person photo */}
                <img
                  src={smileImages[i]}
                  alt={`Happy smiler ${smiler.name}`}
                  className={`${styles.photo} image-hover-scale ${smiler.bw ? styles.bw : ''}`}
                />

                {/* Top bar — whistle logo top-right */}
                <div className={styles.topBar}>
                  <div className={styles.whistleLogo}>
                    <span className={styles.logoW}>W</span>
                    <span className={styles.logoText}>whistle</span>
                    <span className={styles.logoSub}>AND SMILE</span>
                  </div>
                </div>

                {/* Big quote mark bottom-left */}
                <div className={styles.quoteWrap}>
                  <span className={styles.quote}>"</span>
                </div>

                {/* Bottom label */}
                <div className={styles.bottomBar}>
                  <p className={styles.happyLabel}>HAPPY- MONIALS</p>
                  <p className={styles.byLabel}>BY WHISTLE</p>
                </div>

              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
